import java.util.*;

public class TestCase {
    public enum Type { UNIT, INTEGRATION, END_TO_END }

    private String name;
    private Type type;
    private String scope;
    private boolean dependsOnExternalSystem;

    public TestCase(String name, Type type, String scope, boolean dependsOnExternalSystem) {
        this.name = name; this.type = type;
        this.scope = scope; this.dependsOnExternalSystem = dependsOnExternalSystem;
    }

    public Type getType() { return type; }
    public boolean dependsOnExternal() { return dependsOnExternalSystem; }

    @Override
    public String toString() {
        return String.format("[%s] %s (scope: %s, external: %s)", type, name, scope, dependsOnExternalSystem);
    }
}

public class TestSuite {
    private List<TestCase> tests = new ArrayList<>();

    public void add(TestCase test) { tests.add(test); }

    public Map<TestCase.Type, List<TestCase>> groupByType() {
        // TODO: Group tests by Type using a LinkedHashMap
        return new LinkedHashMap<>();
    }

    public double getTestPyramidHealth() {
        // TODO: Return ratio: unit tests should be >= 60% for a healthy pyramid
        // Return as percentage: e.g., 70.0 means 70%
        return 0.0;
    }
}

public class Main {
    public static void main(String[] args) {
        TestSuite suite = new TestSuite();

        // Unit tests
        suite.add(new TestCase("calculateTax_positiveAmount", TestCase.Type.UNIT, "TaxService", false));
        suite.add(new TestCase("calculateTax_zeroAmount", TestCase.Type.UNIT, "TaxService", false));
        suite.add(new TestCase("validateEmail_validFormat", TestCase.Type.UNIT, "Validator", false));
        suite.add(new TestCase("validateEmail_invalidFormat", TestCase.Type.UNIT, "Validator", false));

        // Integration tests
        suite.add(new TestCase("saveUser_persistsToDatabase", TestCase.Type.INTEGRATION, "UserRepository", true));
        suite.add(new TestCase("createOrder_updatesInventory", TestCase.Type.INTEGRATION, "OrderService", true));

        // E2E tests
        suite.add(new TestCase("checkoutFlow_completePurchase", TestCase.Type.END_TO_END, "Full Stack", true));

        Map<TestCase.Type, List<TestCase>> grouped = suite.groupByType();
        grouped.forEach((type, tests) -> {
            System.out.println(type + " tests (" + tests.size() + "): ");
            tests.forEach(t -> System.out.println("  " + t));
        });

        double unitPercentage = suite.getTestPyramidHealth();
        System.out.printf("Unit test percentage: %.1f%% (%s)%n",
            unitPercentage, unitPercentage >= 60 ? "Healthy" : "Needs more unit tests");
    }
}

public class Calculator {
    public double add(double a, double b) {
        return a + b;
    }

    public double subtract(double a, double b) {
        return a - b;
    }

    public double multiply(double a, double b) {
        return a * b;
    }

    public double divide(double a, double b) {
        if (b == 0) throw new ArithmeticException("Division by zero is not allowed");
        return a / b;
    }

    public double power(double base, int exponent) {
        if (exponent < 0) throw new IllegalArgumentException("Negative exponents not supported");
        double result = 1;
        for (int i = 0; i < exponent; i++) result *= base;
        return result;
    }

    public double squareRoot(double n) {
        if (n < 0) throw new IllegalArgumentException("Cannot calculate square root of negative number");
        return Math.sqrt(n);
    }
}

// Manual test framework
public class TestRunner {
    private int passed = 0;
    private int failed = 0;

    public void assertEquals(String testName, double expected, double actual, double delta) {
        if (Math.abs(expected - actual) <= delta) {
            System.out.println("PASS: " + testName);
            passed++;
        } else {
            System.out.println("FAIL: " + testName + " | Expected: " + expected + " | Actual: " + actual);
            failed++;
        }
    }

    public void assertThrows(String testName, Runnable action, Class<? extends Exception> expectedType) {
        try {
            action.run();
            System.out.println("FAIL: " + testName + " | Expected exception was not thrown");
            failed++;
        } catch (Exception e) {
            if (expectedType.isInstance(e)) {
                System.out.println("PASS: " + testName);
                passed++;
            } else {
                System.out.println("FAIL: " + testName + " | Wrong exception: " + e.getClass().getSimpleName());
                failed++;
            }
        }
    }

    public void printSummary() {
        System.out.println("\nTest Results: " + passed + " passed, " + failed + " failed");
    }
}

