import java.util.*;

public class CoverageTracker {
    private Set<String> coveredMethods = new HashSet<>();
    private Set<String> allMethods = new LinkedHashSet<>();

    public void registerMethod(String className, String methodName) {
        allMethods.add(className + "." + methodName);
    }

    public void markCovered(String className, String methodName) {
        String key = className + "." + methodName;
        if (!allMethods.contains(key)) throw new RuntimeException("Unknown method: " + key);
        coveredMethods.add(key);
    }

    public double getMethodCoverage() {
        // TODO: Return percentage of covered methods
        return 0.0;
    }

    public List<String> getUncoveredMethods() {
        // TODO: Return methods in allMethods but not in coveredMethods
        return new ArrayList<>();
    }

    public void printReport() {
        System.out.printf("Method Coverage: %.1f%% (%d/%d methods)%n",
            getMethodCoverage(), coveredMethods.size(), allMethods.size());
        List<String> uncovered = getUncoveredMethods();
        if (!uncovered.isEmpty()) {
            System.out.println("Uncovered methods:");
            uncovered.forEach(m -> System.out.println("  - " + m));
        } else {
            System.out.println("Full coverage achieved!");
        }
    }
}

public class Main {
    public static void main(String[] args) {
        CoverageTracker tracker = new CoverageTracker();

        // Register all methods in the class
        String cls = "UserService";
        tracker.registerMethod(cls, "createUser");
        tracker.registerMethod(cls, "findUser");
        tracker.registerMethod(cls, "updateUser");
        tracker.registerMethod(cls, "deleteUser");
        tracker.registerMethod(cls, "validateUser");

        // Simulate test execution covering some methods
        tracker.markCovered(cls, "createUser");
        tracker.markCovered(cls, "findUser");
        tracker.markCovered(cls, "validateUser");

        tracker.printReport();

        // Cover remaining methods
        tracker.markCovered(cls, "updateUser");
        tracker.markCovered(cls, "deleteUser");
        System.out.println("\nAfter adding more tests:");
        tracker.printReport();
    }
}
